import React from 'react'
import {Row} from "react-bootstrap"
import CardMovie from './CardMovie'
import AdvancedPagination from './Pagenation'
const Movieslist = ({Movies,CurrentPage,pageCount}) => {








    
    return (
        <Row className='mt-3'>
            {
                Movies.length >= 1 ? (Movies.map((movie)=>{
                    return (
                            <CardMovie key={movie.id} movie={movie}/>
                    )
                })): 
                <h2 className='text-center p-5'>No Available Movies at The Mean Time</h2>
            }
            {Movies.length >= 1 ? (<AdvancedPagination CurrentPage={CurrentPage} pageCount={pageCount}/>)
            : null}
            
        </Row>
    )
}

export default Movieslist
